var name = "张三";
var age = 25;

// 可重复声明
var name = "李四"; // 不报错

// 变量提升
console.log(name); // undefined
var name = "张三";
```

### 2. let（块级作用域，推荐）
```javascript
let name = "张三";
let age = 25;

// 不可重复声明
// let name = "李四"; // 报错

// 块级作用域
{
    let blockScoped = "块内变量";
}
// console.log(blockScoped); // 报错
```

### 3. const（块级作用域，常量）
```javascript
