# 1.2 函数与作用域

函数是 JavaScript 的核心概念，它是可重用的代码块。作用域决定了变量的可访问范围。

## 一、函数定义

### 1. 函数声明（命名函数）
```javascript
function greet(name) {
    return "Hello, " + name + "!";
}

// 函数声明会被提升（可在声明前调用）
console.log(greet("张三")); // "Hello, 张三!"
```

### 2. 函数表达式（匿名函数）
```javascript
const greet = function(name) {
    return "Hello, " + name + "!";
};

// 不会被提升
// console.log(greet("张三")); // 报错
```

### 3. 箭头函数（ES6）
```javascript
const greet = (name) => {
    return "Hello, " + name + "!";
};

// 简化形式（单行返回）
const greet = name => "Hello, " + name + "!";

// 无参数
const sayHello = () => "Hello!";

// 多参数
const add = (a, b) => a + b;
```

### 4. 立即执行函数（IIFE）
```javascript
(function() {
    console.log("立即执行");
})();

// 带参数
(function(name) {
    console.log("Hello, " + name);
})("张三");

// 箭头函数写法
(() => {
    console.log("立即执行");
})();
```

---

## 二、参数

### 1. 默认参数
```javascript
function greet(name = "张三") {
    return "Hello, " + name + "!";
}

console.log(greet());       // "Hello, 张三!"
console.log(greet("李四")); // "Hello, 李四!"
```

### 2. 剩余参数
```javascript
function sum(...nums) {
    return nums.reduce((total, num) => total + num, 0);
}

console.log(sum(1, 2, 3));     // 6
console.log(sum(1, 2, 3, 4));  // 10
```

### 3. 解构参数
```javascript
function createUser({ name, age, city = "北京" }) {
    return { name, age, city };
}

const user = createUser({ name: "张三", age: 25 });
console.log(user); // { name: "张三", age: 25, city: "北京" }
```

### 4. 参数验证
```javascript
function divide(a, b) {
    if (typeof a !== "number" || typeof b !== "number") {
        throw new Error("参数必须是数字");
    }
    if (b === 0) {
        throw new Error("除数不能为零");
    }
    return a / b;
}
```

---

## 三、返回值

```javascript
// 显式返回
function add(a, b) {
    return a + b;
}

// 隐式返回（undefined）
function noReturn() {
    console.log("没有返回值");
}

// 返回对象（注意括号）
const getUser = () => ({ name: "张三", age: 25 });

// 提前返回
