## 四、作用域

### 1. 作用域链
```javascript
let global = "全局变量";

function outer() {
    let outer = "外层变量";

    function inner() {
        let inner = "内层变量";
        console.log(global); // 可访问全局
        console.log(outer);  // 可访问外层
        console.log(inner);  // 可访问内层
    }

    inner();
    // console.log(inner); // 报错：无法访问内层变量
}

outer();
```

### 2. 块级作用域
```javascript
// var：函数作用域
function testVar() {
    if (true) {
        var x = 10;
    }
    console.log(x); // 10（var 会泄露到函数作用域）
}

// let/const：块级作用域
function testLet() {
    if (true) {
        let y = 10;
    }
    console.log(y); // 报错：y 在块外不可访问
}
```

### 3. 作用域示例
```javascript
let globalVar = "全局";

function testScope() {
    let functionVar = "函数局部";

    if (true) {
        let blockVar = "块级局部";
        console.log(globalVar);    // ✅
        console.log(functionVar);  // ✅
        console.log(blockVar);     // ✅
    }

    console.log(globalVar);        // ✅
    console.log(functionVar);      // ✅
    // console.log(blockVar);      // ❌ 报错
}
```

---

## 五、闭包

### 定义
闭包是指函数能够访问其外部作用域的变量，即使外部函数已经执行完毕。

### 示例
```javascript
function outer() {
    let count = 0;

    return function() {
        count++;
        console.log(count);
    };
}

const counter = outer();
counter(); // 1
counter(); // 2
counter(); // 3

// 每次调用 counter，都可以访问 outer 中的 count 变量
```

### 应用场景
```javascript
// 1. 数据私有化
function createCounter() {
    let count = 0;
    return {
        increment: () => ++count,
        decrement: () => --count,
        getCount: () => count,
    };
}

const counter = createCounter();
counter.increment();
console.log(counter.getCount()); // 1
// counter.count 无法直接访问

// 2. 函数工厂
function makeGreeter(greeting) {
    return function(name) {
        console.log(greeting + ", " + name + "!");
    };
}

const sayHello = makeGreeter("Hello");
const sayHi = makeGreeter("Hi");

sayHello("张三"); // "Hello, 张三!"
sayHi("李四");   // "Hi, 李四!"
```

---

## 六、this 关键字

### 1. 普通函数
```javascript
// 严格模式下 this 为 undefined
function test() {
    "use strict";
    console.log(this); // undefined
}
test();

// 非严格模式
function test2() {
    console.log(this); // window（浏览器）
}
test2();
```

### 2. 对象方法
```javascript
const person = {
    name: "张三",
    greet: function() {
        console.log(this.name); // "张三"（指向 person）
    }
};
person.greet();
```

### 3. 箭头函数
```javascript
const person = {
    name: "张三",
    greet: () => {
        console.log(this.name); // undefined（箭头函数没有绑定 this）
    },
    greet2: function() {
        const arrow = () => {
            console.log(this.name); // "张三"（继承外层 this）
        };
        arrow();
    }
};
person.greet();  // undefined
person.greet2(); // "张三"
```

### 4. call/apply/bind
```javascript
function greet(greeting = "你好") {
    console.log(greeting + ", " + this.name + "!");
}

const person = { name: "张三" };

// call
greet.call(person, "你好"); // "你好, 张三!"

// apply（参数以数组形式传递）
greet.apply(person, ["您好"]); // "您好, 张三!"

// bind（返回新函数）
const boundGreet = greet.bind(person);
boundGreet("哈喽"); // "哈喽, 张三!"
```

---

## 七、高阶函数

函数作为参数或返回值的函数。

### 1. 函数作为参数
```javascript
function operate(a, b, operation) {
    return operation(a, b);
}

function add(a, b) {
    return a + b;
}

function multiply(a, b) {
    return a * b;
}

console.log(operate(5, 3, add));       // 8
console.log(operate(5, 3, multiply)); // 15
```

### 2. 函数作为返回值
```javascript
function multiplyBy(n) {
    return function(x) {
        return x * n;
    };
}

const double = multiplyBy(2);
const triple = multiplyBy(3);

console.log(double(5));  // 10
console.log(triple(5));  // 15
```

### 3. 常用高阶函数
```javascript
const nums = [1, 2, 3, 4, 5];

// map：映射
const doubled = nums.map(n => n * 2);
console.log(doubled); // [2, 4, 6, 8, 10]

// filter：过滤
const evens = nums.filter(n => n % 2 === 0);
console.log(evens); // [2, 4]

// reduce：归约
const sum = nums.reduce((total, n) => total + n, 0);
console.log(sum); // 15

// forEach：遍历
nums.forEach(n => console.log(n));

// find：查找
const found = nums.find(n => n > 3);
console.log(found); // 4

// some：是否存在满足条件的
const hasEven = nums.some(n => n % 2 === 0);
console.log(hasEven); // true

// every：是否都满足条件
const allPositive = nums.every(n => n > 0);
console.log(allPositive); // true
```

---

## 八、递归

函数调用自身。

```javascript
// 阶乘
function factorial(n) {
    if (n === 0 || n === 1) {
        return 1;
    }
    return n * factorial(n - 1);
}

console.log(factorial(5)); // 120

// 斐波那契数列
function fibonacci(n) {
    if (n === 0) return 0;
    if (n === 1) return 1;
    return fibonacci(n - 1) + fibonacci(n - 2);
}

console.log(fibonacci(10)); // 55
```

---

## 九、总结

- 函数声明会被提升，表达式不会
- 箭头函数没有自己的 this，继承外层
- 闭包让函数能访问外部作用域变量
- 高阶函数让代码更简洁、可复用
- 递归要设置终止条件，避免栈溢出

# 1.3 对象与数组

对象和数组是 JavaScript 中最重要的数据结构，用于存储和组织数据。

## 一、对象（Object）

### 1. 创建对象
```javascript
// 对象字面量
const person = {
    name: "张三",
    age: 25,
    city: "北京",
    greet: function() {
        console.log("Hello!");
    }
};

// new Object()
const person2 = new Object();
person2.name = "李四";
person2.age = 30;

// 工厂函数
function createPerson(name, age) {
    return {
        name,
        age,
        greet() {
            console.log(`Hello, I'm ${this.name}`);
        }
    };
}

const person3 = createPerson("王五", 28);

// 构造函数
function Person(name, age) {
    this.name = name;
    this.age = age;
    this.greet = function() {
        console.log(`Hello, I'm ${this.name}`);
    };
}

const person4 = new Person("赵六", 27);
```

### 2. 访问属性
```javascript
const person = {
    name: "张三",
    age: 25,
    "full name": "张三丰"
};

// 点表示法
console.log(person.name);        // "张三"

// 方括号表示法
console.log(person["age"]);      // 25
console.log(person["full name"]);// "张三丰"（必须用于特殊属性名）

// 动态属性名
const key = "name";
console.log(person[key]);        // "张三"
```

### 3. 添加/修改/删除属性
```javascript
const person = { name: "张三" };

// 添加属性
person.age = 25;
person.city = "北京";

// 修改属性
person.name = "李四";

// 删除属性
delete person.city;

// Object.defineProperty（定义属性）
const obj = {};
Object.defineProperty(obj, "name", {
    value: "张三",
    writable: true,   // 可写
    enumerable: true, // 可遍历
    configurable: true, // 可删除
    get() {
        return "张三";
    },
    set(value) {
        // 设置逻辑
    }
});
```

### 4. 对象方法
```javascript
const person = {
    name: "张三",
    age: 25,

    greet() {
        console.log(`Hello, I'm ${this.name}`);
    },

    sayHello: function() {
        console.log(`Hello!`);
    }
};

person.greet();     // 调用方法
person["greet"](); // 另一种方式
```

### 5. 遍历对象
```javascript
const person = { name: "张三", age: 25, city: "北京" };

// for...in
for (let key in person) {
    console.log(key, person[key]);
}

// Object.keys()
console.log(Object.keys(person)); // ["name", "age", "city"]

// Object.values()
console.log(Object.values(person)); // ["张三", 25, "北京"]

// Object.entries()
console.log(Object.entries(person)); // [["name", "张三"], ["age", 25], ["city", "北京"]]

// Object.fromEntries()
const entries = [["name", "张三"], ["age", 25]];
console.log(Object.fromEntries(entries)); // { name: "张三", age: 25 }
```

### 6. 对象解构
```javascript
const person = { name: "张三", age: 25, city: "北京" };

// 基本解构
const { name, age } = person;

// 重命名
const { name: userName, age: userAge } = person;

// 默认值
const { name, country = "中国" } = person;

// 嵌套解构
const user = {
    name: "张三",
    address: {
        city: "北京",
        street: "长安街"
    }
};

const {
    address: { city }
} = user;

// 解构剩余属性
const { name: userName, ...rest } = person;
console.log(rest); // { age: 25, city: "北京" }
```

### 7. 对象展开
```javascript
const person = { name: "张三", age: 25 };

// 合并对象
const newPerson = { ...person, city: "北京" };
console.log(newPerson); // { name: "张三", age: 25, city: "北京" }

// 修改属性
const updatedPerson = { ...person, age: 26 };
console.log(updatedPerson); // { name: "张三", age: 26 }

// Object.assign
const obj1 = { a: 1 };
const obj2 = { b: 2 };
const merged = Object.assign({}, obj1, obj2);
console.log(merged); // { a: 1, b: 2 }
```

