    visibility: hidden;
}

/* 显示元素 */
element {
    visibility: visible;
}

/* 折叠（主要用于表格） */
element {
    visibility: collapse;
}

/* display: none 与 visibility: hidden 的区别 */
/* display: none: 不占据空间，不响应事件 */
/* visibility: hidden: 占据空间，不响应事件 */
```

